import express from 'express';
import { Autumn } from 'autumn-js';

const app = express();
app.use(express.json());

// Initialize Autumn SDK with secret key from environment
const autumn = new Autumn({
  secretKey: process.env.AUTUMN_SECRET_KEY,
});

app.get('/health', (req, res) => {
  res.json({ status: 'ok' });
});

app.post('/check-access', async (req, res) => {
  try {
    const { customerId, featureId } = req.body;

    if (!customerId || !featureId) {
      return res.status(400).json({
        error: 'Bad Request',
        message: 'customerId and featureId are required'
      });
    }

    // Call Autumn's check endpoint
    const response = await autumn.check({ customerId, featureId });

    // Respond with appropriate status code based on allowed field
    if (response.allowed) {
      return res.status(200).json(response);
    } else {
      return res.status(403).json(response);
    }
  } catch (error) {
    console.error('Error checking access:', error);
    return res.status(500).json({
      error: 'Internal Server Error',
      message: error.message
    });
  }
});

app.listen(3000, () => {
  console.log('Server running on port 3000');
});
